#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,b,h[20004];
    cin>>n>>b;
    for(int i=1;i<=n;i++)
        cin>>h[i];
    sort(h+1,h+n+1,greater<int>());
    int sum=0;
    for(int i=1;i<=n;i++){
        sum+=h[i];
        if(sum>=b){
            cout<<i;
            break;
        }
    }
    return 0;
}
